import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Define a maximum buffer size to prevent buffer overflow
        int bufferSize = 10;

        // Check if the input length exceeds the buffer size
        if (input.length() > bufferSize) {
            System.out.println("Input exceeds maximum length. Please enter a shorter name.");
            return;
        }

        // Safe code - using an array with fixed size and ensuring proper copying
        char[] buffer = new char[bufferSize];

        // Copying user input into the buffer
        for (int i = 0; i < input.length(); i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Your name is: " + new String(buffer));
    }
}

